n},\n{\n\"start_time\": \"05:15\",\n\"end_time\": \"06:15\",\n\"duration_hours\": 1.0,\n\"activity\": \"Weld on casing bowl\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"06:15\",\n\"end_time\": \"06:30\",\n\"duration_hours\": 0.25,\n\"activity\": \"Safety meeting / Crew change - With Rig Manager and ARC Rep, LSR - Hot work\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"06:30\",\n\"end_time\": \"07:45\",\n\"duration_hours\": 1.25,\n\"activity\": \"Weld on casing bowl\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"07:45\",\n\"end_time\": \"08:00\",\n\"duration_hours\": 0.25,\n\"activity\": \"Safety meeting prior to Nippling up\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"08:00\",\n\"end_time\": \"16:30\",\n\"duration_hours\": 8.5,\n\"activity\": \"Nipple up BOPs, install bowl valves, install speed head, install kill valves, HCR valves, choke lines, Flare and degasser lines\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"16:30\",\n\"end_time\": \"18:00\",\n\"duration_hours\": 1.5,\n\"activity\": \"Nipple up MPD\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"18:00\",\n\"end_time\": \"18:15\",\n\"duration_hours\": 0.25,\n\"activity\": \"Pressure Test BOP, Upper rams, lower rams, blind rams, All Inside and outside choke and kill valves, check valves, HCR, HCR, Inside BOP, stabbing valve lower kelly Valve, choke line, all manifold valves 1,400kpa low and 34,500 kpa highfor 10 min each test. Annular, casing, casing bowl valves and speed head valves 1,400kpa low and 17,250kpa high for 10 min each test\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"18:15\",\n\"end_time\": \"18:30\",\n\"duration_hours\": 0.25,\n\"activity\": \"Safety meeting / Crew change - With Rig Manager and ARC Rep, LSR - Line of Fire\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"18:30\",\n\"end_time\": \"20:00\",\n\"duration_hours\": 1.5,\n\"activity\": \"Pressure Test BOP, Upper rams, lower rams, blind rams, All Inside and outside choke and kill valves, check valves, HCR, HCR, Inside BOP, stabbing valve lower kelly Valve, choke line, all manifold valves 1,400kpa low and 34,500 kpa highfor 10 min each test. Annular, casing, casing bowl valves and speed head valves 1,400kpa low and 17,250kpa high for 10 min each test\",\n\"depth_md\": null,\n\"comment\": null\n},\n{\n\"start_time\": \"20:00\",\n\"end_time\": \"24:00\",\n\"duration_hours\": 4.0,\n\"activity\": \"Pressure Test BOP, Upper rams, lower rams, blind rams, All Inside and outside choke and kill valves, check valves, HCR, HCR, Inside BOP, stabbing valve lower kelly Valve, choke line, all manifold valves 1,400kpa low and 34,500 kpa highfor 10 min each test. Annular, casing, casing bowl valves and speed head valves 1,400kpa low and 17,250kpa high for 10 min each test\",\n\"depth_md\": null,\n\"comment\": null\n}\n],\n\"mud_records\": [],\n\"deviation_surveys\": [],\n\"bit_records\": []\n}"}','{"time_logs": [{"comment": null, "activity": "Run 244.5mm surface casing from 589m to 628m, 150 ton side door elevators cert # HC909", "depth_md": null, "end_time": "00:15", "start_time": "00:00", "duration_hours": 0.25}, {"comment": null, "activity": "circulate landing joint down cleaning up bottom hole, 2m of fill", "depth_md": null, "end_time": "01:15", "start_time": "00:15", "duration_hours": 1.0}, {"comment": null, "activity": "Safety meeting w/ trican cementers", "depth_md": null, "end_time": "01:30", "start_time": "01:15", "duration_hours": 0.25}, {"comment": null, "activity": "Rig in Cementers, Cement 50 joints of 244.5mm surface casing from 628m to 6.60m. Pump 1m³ of Opti ahead and pressure test lines to 19MPa. Pump 3m³ of Opti weighted to 1250kg/m³. Pump 34.5m³ (33 tonne / 90% excess) of cement at a density of 1750kg/m³. Drop plug on the fly, and displace with 24.8m³ of fresh water. Plug down @ 03:12hrs. Pressure test casing to 17mPa hold