	 ('77a227ac-75a2-4603-b179-f1ab1d1d0b10'::uuid,'c5f071d7-29ee-403c-9352-25d0e004e2a1'::uuid,'20210927','success','{"text": "{\n\"well_name\": \"7 GEN HZ 102 KAKWA 13-34-62-4\",\n\"surface_location\": \"06-26-062-04W6\",\n\"time_logs\": [\n{\n\"start_time\": \"00:00\",\n\"end_time\": \"04:30\",\n\"duration_hours\": 4.5,\n\"activity\": \"Trip in hole w/ 8 3/4\\\" directional BHA. Tagged btm @3253m. Ran leak off test, held 2.9mPa/L with 1.15sg mud. Squeezed off the hole. Functioned RAMS and closed annular. RIH to 3253m, broke circulation. Washed and reamed last 6 joints. Drilled cement and float collar from 3253m-3270m. Drilled shoe and new formation from 3270m-3286m. Washed and reamed from 3286m-3270m. Circulated hole clean. Pulled back into casing and shut down draw works.\",\n\"depth_md\": 3286.0,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"04:30\",\n\"end_time\": \"04:45\",\n\"duration_hours\": 0.25,\n\"activity\": \"Waiting on parts. Replaced accumulator solenoid.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"04:45\",\n\"end_time\": \"07:00\",\n\"duration_hours\": 2.25,\n\"activity\": \"RIH to 3286m. Pumped slug. Layed down BHA #4.\",\n\"depth_md\": 3286.0,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"07:00\",\n\"end_time\": \"07:15\",\n\"duration_hours\": 0.25,\n\"activity\": \"Rig in hybrid casing service.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"07:15\",\n\"end_time\": \"11:45\",\n\"duration_hours\": 4.5,\n\"activity\": \"Run 177.8mm 40.2kg/m P110 USSF casing. RU DB CRC crew and ARC CRS prior to running casing. Makeup up 177.8mm single and shoe track consisting of a 177.8mm L80 LTC landing collar, 177.8mm L80 LTC float collar, 177.8mm P110 USSF reamer shoe, 1 BBL LTC SheathMud MI filler collar, Fill up and check floats periodically. RIH to 3280m. Lost 1m^3 on run in. Pumped 12m^3 1.05sg kill mud with sweeps, got full returns. Continued to run to TD @ 3286m. Filled casing up and top up every 20 joints. Run 177.8mm 40.2kg/m P110 USSF casing to 3286m. Filled casing up. Circulated 1.5 bottoms up. Shut down to rig up cementers. Waiting on cementers.\",\n\"depth_md\": 3286.0,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"11:45\",\n\"end_time\": \"12:00\",\n\"duration_hours\": 0.25,\n\"activity\": \"Rig up cementers. Safety meeting.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"12:00\",\n\"end_time\": \"17:00\",\n\"duration_hours\": 5.0,\n\"activity\": \"Wait on cementers to rig in. Cement 177.8mm 40.2kg/m P110 USSF casing to 3286m as per program. Bumped plug at 15:15 to 22.5mPa with good returns. Set slips, cut casing. Nipple down BOP.\",\n\"depth_md\": 3286.0,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"17:00\",\n\"end_time\": \"18:00\",\n\"duration_hours\": 1.0,\n\"activity\": \"Safety Meeting\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"18:00\",\n\"end_time\": \"19:15\",\n\"duration_hours\": 1.25,\n\"activity\": \"Nipple up 18 3/4\\\" 10k annular and 18 3/4\\\" 10k double gate over 18 3/4\\\" 10k single ram. Install wear bushing.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"19:15\",\n\"end_time\": \"20:15\",\n\"duration_hours\": 1.0,\n\"activity\": \"Function test and pressure test blind rams, pipe rams, HCR''s and choke manifold to 21mPa low and 35mPa high. Function test annular. Received test chart for all tests.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"20:15\",\n\"end_time\": \"20:30\",\n\"duration_hours\": 0.25,\n\"activity\": \"Continue running in hole from 2932m to 3270m. Pick up landing joint and wash to TD @3286m. Circulate hole clean prior to testing.\",\n\"depth_md\": 3286.0,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"20:30\",\n\"end_time\": \"21:15\",\n\"duration_hours\": 0.75,\n\"activity\": \"Leak off test performed. Held 4.5mPa/L\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 67\n},\n{\n\"start_time\": \"21:15\",\n\"end_time\": \"24:00\",\n\"duration_hours\": 2.75,\n\"activity\": \"Drill out cement and shoe at 3286m. Rig in connections while circulating.\",\n\"depth_md\": 3286.0,\n\"comment\": null,\n\"page_number\": 67\n}\n],\n\"mud_records\": [\n{\n\"depth_md\": 3286.0,\n\"mud_weight\": 1.15,\n\"viscosity\": 56.0,\n\"ph\": 9.0,\n\"comment\": \"Location of Sample: SHAKERS\"\n},\n{\n\"depth_md\": 3286.0,\n\"mud_weight\": 1.05,\n\"viscosity\": 32.0,\n\"ph\": 9.0,\n\"comment\": \"Location of Sample: SHAKERS\"\n}\n],\n\"deviation_surveys\": [],\n\"bit_records\": [\n{\n\"bit_number\": \"1\",\n\"bit_size\": 222.0,\n\"depth_in\": 3190.0,\n\"depth_out\": 3286.0,\n\"hours\": 5.0,\n\"comment\": \"IADC: M323, Manufacturer: Smith, Type: MDi616PX\"\n},\n{\n\"bit_number\": \"2\",\n\"bit_size\": 156.0,\n\"depth_in\": 3286.0,\n\"depth_out\": 3286.0,\n\"hours\": 0.0,\n\"comment\": \"IADC: M423, Manufacturer: Smith, Type: MDi516\"\n}\n]\n}"}','{"time_logs": [{"comment": null, "activity": "Trip in hole w/ 8 3/4\" directional BHA. Tagged btm @3253m. Ran leak off test, held 2.9mPa/L with 1.15sg mud. Squeezed off the hole. Functioned RAMS and closed annular. RIH to 3253m, broke circulation. Washed and reamed last 6 joints. Drilled cement and float collar from 3253m-3270m. Drilled shoe and new formation from 3270m-3286m. Washed and reamed from 3286m-3270m. Circulated hole clean. Pulled back into casing and shut down draw works.", "depth_md": 3286.0, "end_time": "04:30", "start_time": "00:00", "page_number": 67, "duration_hours": 4.5}, {"comment": null, "activity": "Waiting on parts. Replaced accumulator solenoid.", "depth_md": null, "end_time": "04:45", "start_time": "04:30", "page_number": 67, "duration_hours": 0.25}, {"comment": null, "activity": "RIH to 3286m. Pumped slug. Layed down BHA