	 ('25307bbb-f4ca-46a9-b57c-a05a398473fe'::uuid,'c5f071d7-29ee-403c-9352-25d0e004e2a1'::uuid,'20210729','success','{"text": "{\n\"well_name\": \"7 GEN HZ 102 KAKWA 13-34-62-4\",\n\"surface_location\": \"06-26-062-04W6\",\n\"time_logs\": [\n{\n\"start_time\": \"19:15\",\n\"end_time\": \"21:00\",\n\"duration_hours\": 1.75,\n\"activity\": \"Safety meeting with Trican and rig up cementers. Pump 1m3 water w/ red dye & Pressure test lines to 19MPa. Pump 2.5m3 Optiflush (3kg/m3 OF-3) at 1250kg/m3 ahead, 2.5m3 (1.3ton)T-Mix II Scavenger @ 1350kg/m3, 39.17m3 (43.72T - 100% excess) T-Mix II cement with 2% LCM-3, 0.4% AFA-7, 0.4% CFL-2 at 1750kg/m3 at 0.9m3/min. Drop top plug on the fly and displace with 24.64m3 water at 1000kg/m3. Plug down July 29, 2021 @ 21:00hrs. Good returns when the plug was dropped for the first 14m3. Returns began to drop off so the displacement rate was dropped from 1m3/min to 0.7m3/min. Returns remained low until the plug was bumped with traces of red dye in the cellar, no cement returns to surface. Bump plug 3.5MPa over FCP (6MPa.) Bleed off and check floats. Floats held, 300L back. Pressure test casing to low of 1,400kpa low and high of 17,000kpa for 11mins each.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 7\n},\n{\n\"start_time\": \"21:00\",\n\"end_time\": \"21:15\",\n\"duration_hours\": 0.25,\n\"activity\": \"Rig out cementers\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 7\n},\n{\n\"start_time\": \"21:15\",\n\"end_time\": \"21:30\",\n\"duration_hours\": 0.25,\n\"activity\": \"Lay down landing joint\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 7\n},\n{\n\"start_time\": \"21:30\",\n\"end_time\": \"22:00\",\n\"duration_hours\": 0.5,\n\"activity\": \"Rig out and prepare to walk drilling package from 102/13-34-062-04W6 to 103/16-33-062-04W6. Rig released on July 29, 2021 at 22:00hrs.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 7\n}\n],\n\"mud_records\": [\n{\n\"depth_md\": 595.0,\n\"mud_weight\": 1.18,\n\"viscosity\": 50.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.2,\n\"viscosity\": 58.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.21,\n\"viscosity\": 74.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.14,\n\"viscosity\": 55.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.14,\n\"viscosity\": 50.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.11,\n\"viscosity\": 40.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.16,\n\"viscosity\": 55.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.15,\n\"viscosity\": 44.0,\n\"ph\": null,\n\"comment\": null\n},\n{\n\"depth_md\": 655.0,\n\"mud_weight\": 1.15,\n\"viscosity\": 44.0,\n\"ph\": null,\n\"comment\": null\n}\n],\n\"deviation_surveys\": [],\n\"bit_records\": []\n}"}','{"time_logs": [{"comment": null, "activity": "Safety meeting with Trican and rig up cementers. Pump 1m3 water w/ red dye & Pressure test lines to 19MPa. Pump 2.5m3 Optiflush (3kg/m3 OF-3) at 1250kg/m3 ahead, 2.5m3 (1.3ton)T-Mix II Scavenger @ 1350kg/m3, 39.17m3 (43.72T - 100% excess) T-Mix II cement with 2% LCM-3, 0.4% AFA-7, 0.4% CFL-2 at 1750kg/m3 at 0.9m3/min. Drop top plug on the fly and displace with 24.64m3 water at 1000kg/m3. Plug down July 29, 2021 @ 21:00hrs. Good returns when the plug was dropped for the first 14m3. Returns began to drop off so the displacement rate was dropped from 1m3/min to 0.7m3/min. Returns remained low until the plug was bumped with traces of red dye in the cellar, no cement returns to surface. Bump plug 3.5MPa over FCP (6MPa.) Bleed off and check floats. Floats held, 300L back. Pressure test casing to low of 1,400kpa low and high of 17,000kpa for 11mins each.", "depth_md": null, "end_time": "21:00", "start_time": "19:15", "page_number": 7, "duration