	 ('3c685726-182f-46c4-be09-766380fc25d9'::uuid,'c5f071d7-29ee-403c-9352-25d0e004e2a1'::uuid,'20210728','success','{"text": "{\n\"well_name\": \"7 GEN HZ 102 KAKWA 13-34-62-4\",\n\"surface_location\": \"06-26-062-04W6\",\n\"time_logs\": [\n{\n\"start_time\": \"08:45\",\n\"end_time\": \"10:00\",\n\"duration_hours\": 1.25,\n\"activity\": \"Wait on tools to arrive. Wait on 3rd party to move in & rig up.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 1\n},\n{\n\"start_time\": \"10:00\",\n\"end_time\": \"10:15\",\n\"duration_hours\": 0.25,\n\"activity\": \"Pre-job safety meeting prior to rig up.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 1\n},\n{\n\"start_time\": \"10:15\",\n\"end_time\": \"12:00\",\n\"duration_hours\": 1.75,\n\"activity\": \"Rig up cementer to well. Pressure test surface casing.\",\n\"depth_md\": null,\n\"comment\": \"Pressure tested to 7000kpa with third party wellhead man on site. Well was spud at 18:15hrs (July,28,2021)\",\n\"page_number\": 1\n},\n{\n\"start_time\": \"12:00\",\n\"end_time\": \"13:45\",\n\"duration_hours\": 1.75,\n\"activity\": \"Nipple up BOP, test blind rams, top pipe ram, bottom pipe ram to 21,000kpa. Bleed off test. Function test open/close.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"13:45\",\n\"end_time\": \"14:00\",\n\"duration_hours\": 0.25,\n\"activity\": \"Pre-job safety meeting. Rig up tools and handle subs.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"14:00\",\n\"end_time\": \"15:45\",\n\"duration_hours\": 1.75,\n\"activity\": \"Pick up bit, motor, MWD and directional BHA. Make up to top drive and RIH.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"15:45\",\n\"end_time\": \"17:00\",\n\"duration_hours\": 1.25,\n\"activity\": \"RIH, tag cement, wash to bottom and circulate.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"17:00\",\n\"end_time\": \"17:15\",\n\"duration_hours\": 0.25,\n\"activity\": \"Safety meeting W/ Phoenix directional.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"17:15\",\n\"end_time\": \"18:15\",\n\"duration_hours\": 1.0,\n\"activity\": \"Drill out cement and shoe track. Pressure test up to 21kpa at shoe casing at 215mm. Tested to 2100kpa and 7000kpa @ 215mm for 10mins. Good test. Notified townsite at 18:07\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"18:15\",\n\"end_time\": \"18:45\",\n\"duration_hours\": 0.5,\n\"activity\": \"Drill ahead 15m of new hole. Circulate hole clean.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"18:45\",\n\"end_time\": \"19:15\",\n\"duration_hours\": 0.5,\n\"activity\": \"Circulate and orient toolface. Slide for 30mins.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"19:15\",\n\"end_time\": \"22:45\",\n\"duration_hours\": 3.5,\n\"activity\": \"Drill 231m of new hole from 234m to 465m. Build inclination to 10degrees.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"22:45\",\n\"end_time\": \"23:15\",\n\"duration_hours\": 0.5,\n\"activity\": \"POOH 2 stands of drillpipe.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n},\n{\n\"start_time\": \"23:15\",\n\"end_time\": \"24:00\",\n\"duration_hours\": 0.75,\n\"activity\": \"Circulate hole clean from 500m to 520m.\",\n\"depth_md\": null,\n\"comment\": null,\n\"page_number\": 2\n}\n],\n\"mud_records\": [\n{\n\"depth_md\": 28.0,\n\"mud_weight\": 1010.0,\n\"viscosity\": 29.0,\n\"ph\": 10.45,\n\"comment\": null\n},\n{\n\"depth_md\": 112.0,\n\"mud_weight\": 1080.0,\n\"viscosity\": 30.0,\n\"ph\": 10.12,\n\"comment\": null\n},\n{\n\"depth_md\": 254.0,\n\"mud_weight\": 1120.0,\n\"viscosity\": 31.0,\n\"ph\": 9.89,\n\"comment\": null\n},\n{\n\"depth_md\": 436.0,\n\"mud_we