	 ('cbffdf7f-e878-4842-b160-c7f650e420f0'::uuid,'c5f071d7-29ee-403c-9352-25d0e004e2a1'::uuid,'20210928','success','{"text": "{\n  \"well_name\": \"7 GEN HZ 102 KAKWA 13-34-62-4\",\n  \"surface_location\": \"06-26-062-04W6\",\n  \"time_logs\": [\n    {\n      \"start_time\": \"00:00\",\n      \"end_time\": \"00:15\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Rig in members. Pump 1m3 OptiKleen pill/push spacer, pressure test lines to 20MPa/2900psi. Displace hole with 5m3 OptiKleen at 1.0m3/min. Displace hole with invert. Neg test csg shoe to -1400kPa/ 1400kPa hold for 10 min. Pos test csg shoe to 14.5MPa/2103psi for 10 min. POOH with bit #3 to surface. Dress off BHA for bit #4\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 70\n    },\n    {\n      \"start_time\": \"00:15\",\n      \"end_time\": \"01:15\",\n      \"duration_hours\": 1.0,\n      \"activity\": \"RIH bit #4 to 3243m. W/O for cement to cure. Circ hole clean for 1 hr. WOP up to 13,000daN.\",\n      \"depth_md\": 3243.0,\n      \"comment\": null,\n      \"page_number\": 70\n    },\n    {\n      \"start_time\": \"01:15\",\n      \"end_time\": \"02:45\",\n      \"duration_hours\": 1.5,\n      \"activity\": \"Drill out shoe and cmt. Cont. drill cmt to 3298m. Circ hole clean and sweep with 4.5m3 hi-vis pill. Displace sweep from hole. Cont. drlg cmt. Drlg plug on top and try and displace with DP card produced water. Plug started to pump away at 20MPa. Let plug go to 3293m. S/W 5m3 1400kg/m3 AFA-X, S/W 200m3 oil based cement to surface. Bleed off and check floats. Floats held. S/W 200m3 oil based cmt to surface again, float held. S/W 10m3 AFA-X, S/W 21.0m3 Invert mud with Pac-R pill. Perform negative pressure test for 10min, bled off no flow. test good.\",\n      \"depth_md\": 3298.0,\n      \"comment\": null,\n      \"page_number\": 70\n    },\n    {\n      \"start_time\": \"02:45\",\n      \"end_time\": \"05:45\",\n      \"duration_hours\": 3.0,\n      \"activity\": \"Pick up and rack out 1 jt of rapid assemble, service lockdown dogs and pressure test to 14MPa for 10 min. Test good. Rack back in derrick.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 70\n    },\n    {\n      \"start_time\": \"05:45\",\n      \"end_time\": \"06:00\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Safety meeting with Praxair, pick up standpipe to BOP.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 70\n    },\n    {\n      \"start_time\": \"12:00\",\n      \"end_time\": \"12:30\",\n      \"duration_hours\": 0.5,\n      \"activity\": \"Continue RIH to 3293m. Wash down 5m.\",\n      \"depth_md\": 3293.0,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"12:30\",\n      \"end_time\": \"13:45\",\n      \"duration_hours\": 1.25,\n      \"activity\": \"Circulate bottoms up. Take sample.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"13:45\",\n      \"end_time\": \"14:30\",\n      \"duration_hours\": 0.75,\n      \"activity\": \"Strap in hole. S/D to perform FIT. Still see BOP dist hold with Praxair. Circulate, kick while checking dist. BOP not holding.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"14:30\",\n      \"end_time\": \"15:45\",\n      \"duration_hours\": 1.25,\n      \"activity\": \"Detailed meeting with crew, discuss kick warning signs and gas kick circulation. Discuss well control.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"15:45\",\n      \"end_time\": \"18:00\",\n      \"duration_hours\": 2.25,\n      \"activity\": \"Start drilling line, 25m slip.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"18:00\",\n      \"end_time\": \"19:45\",\n      \"duration_hours\": 1.75,\n      \"activity\": \"Repair leaking Gray tool. Lay out drill plugs / float / cement shoe from last run. Check cement job data from last report.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"19:45\",\n      \"end_time\": \"20:15\",\n      \"duration_hours\": 0.5,\n      \"activity\": \"POOH to 3000m. No indications of flow.\",\n      \"depth_md\": 3000.0,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"20:15\",\n      \"end_time\": \"21:00\",\n      \"duration_hours\": 0.75,\n      \"activity\": \"RIH to 3293m. Circulate bottoms up.\",\n      \"depth_md\": 3293.0,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"21:00\",\n      \"end_time\": \"22:15\",\n      \"duration_hours\": 1.25,\n      \"activity\": \"S/D to test BOP with Audrey. Bleed well down and crew review shut in procedures and kick sheet. Pressure test blind rams to 20MPa. Test good. Open blinds, pressure test upper pipe rams to 20MPa. Test good.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 71\n    },\n    {\n      \"start_time\": \"22:15\",\n      \"end_time\": \"24:00\",\n      \"duration_hours\": 1.75,\n      \"activity\": \"Drill from 3293m - 3477m. Rotate at 155 rpm. Build and turn from 0° - 4°. Check upper and lower pipe rams to see if it can clear.\",\n      \"depth_md\": 3477.0,\n      \"comment\": null,\n      \"page_number\": 71\n    }\n  ],\n  \"mud_records\": [\n    {\n      \"depth_md\": 3293.0,\n      \"mud_weight\": 1175.0,\n      \"viscosity\": 57.0,\n      \"ph\": null,\n      \"comment\": \"Time: 02:00\"\n    },\n    {\n      \"depth_md\": 3322.0,\n      \"mud_weight\": 1115.0,\n      \"viscosity\": 29.0,\n      \"ph\": 10.5,\n      \"comment\": \"Time: 15:45\"\n    },\n    {\n      \"depth_md\": 3355.0,\n      \"mud_weight\": 1115.0,\n    