	 ('e7b502b8-e38a-444e-8916-edac4463f1f3'::uuid,'85c5b700-a748-4f40-87b2-6349d25ea32b'::uuid,'20210810','success','{"text": "{\n  \"well_name\": \"7GEN HZ 102 KAKWA 16-33-62-4\",\n  \"surface_location\": \"06-26-062-04W6\",\n  \"time_logs\": [\n    {\n      \"start_time\": \"00:00\",\n      \"end_time\": \"04:15\",\n      \"duration_hours\": 4.25,\n      \"activity\": \"Cont running 177.8mm casing from 1828m to 2800M\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"04:15\",\n      \"end_time\": \"07:00\",\n      \"duration_hours\": 2.75,\n      \"activity\": \"Circulate bottoms up in the falher\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"07:00\",\n      \"end_time\": \"07:15\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Crew handover meeting\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"07:15\",\n      \"end_time\": \"08:45\",\n      \"duration_hours\": 1.5,\n      \"activity\": \"Continue to circulate and lower mud weight\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"08:45\",\n      \"end_time\": \"10:30\",\n      \"duration_hours\": 1.75,\n      \"activity\": \"Continue to run 177.8mm casing from 2800m to 3243.48m\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"10:30\",\n      \"end_time\": \"11:45\",\n      \"duration_hours\": 1.25,\n      \"activity\": \"Circulate hole clean prior to cement job\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"11:45\",\n      \"end_time\": \"12:00\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Rig Service-Function test the Annular 18 seconds to close\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"12:00\",\n      \"end_time\": \"13:00\",\n      \"duration_hours\": 1.0,\n      \"activity\": \"Continue to circulate\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"13:00\",\n      \"end_time\": \"13:15\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Safety meeting with cementers prior to rigging in cementers\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"13:15\",\n      \"end_time\": \"15:45\",\n      \"duration_hours\": 2.5,\n      \"activity\": \"CementingRig in cementers to the stump. Pump 2m3 Optimum Flush spacer, pressure test lines to 34MPa. Pump remaining 3m3 (5m3 total) Optimum Flush spacer @ 1300kg/m3 with OF-3 and MS-8. Mix and Pump 5m3(2.8T) Titanium-1400 Scavenger @ 1350kg/m3, 92.47m3(59.2 T - 150% excess) Titanium 1400 Lead Cement @ 1400kg/m3 w/ additives. Followed by 5.75m3 (5.5T - 10% excess ) T.A.C. Tail Cement @ 1600kg/m3 with additives.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"15:45\",\n      \"end_time\": \"16:00\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Safety meeting-Crew change handover\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"16:00\",\n      \"end_time\": \"18:00\",\n      \"duration_hours\": 2.0,\n      \"activity\": \"8m3 of returns to surface. Bleed off and check floats, floats held. Pressure test casing low to 1400KPa for 10mins flat , bleed off. P-test casing to high of 21,000pa for 10 mins flat line, good. Perform negative pressure test for 15min with casing annulus static. Rig out cementing iron and clean up for 15min with casing annulus static. Rig out cementing iron and clean up\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"18:00\",\n      \"end_time\": \"19:45\",\n      \"duration_hours\": 1.75,\n      \"activity\": \"Pull landing joint, make up next wells 7\\\" hanger and lay out to catwalk. Change bails and elevators, install and test 7\\\" pack-off seals w/ Stream truck for road travel.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 1\n    },\n    {\n      \"start_time\": \"19:45\",\n      \"end_time\": \"20:00\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Flo. Install wearbushing and prepare rig floor for BHA.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 2\n    },\n    {\n      \"start_time\": \"20:00\",\n      \"end_time\": \"21:15\",\n      \"duration_hours\": 1.25,\n      \"activity\": \"Safety meeting w/ Phoenix directional\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 2\n    },\n    {\n      \"start_time\": \"21:15\",\n      \"end_time\": \"23:00\",\n      \"duration_hours\": 1.75,\n      \"activity\": \"Make up Directional BHA #5 from 0m - 55m\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 2\n    },\n    {\n      \"start_time\": \"23:00\",\n      \"end_time\": \"23:15\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Trip in hole f/ 55m - 1275m. P/U and test agitator @ 811m. Pressure loss @ 1m3/min before = 4200kpa After = 6400kpa.\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 2\n    },\n    {\n      \"start_time\": \"23:15\",\n      \"end_time\": \"23:45\",\n      \"duration_hours\": 0.5,\n      \"activity\": \"Safety meeting - crew change handover\",\n      \"depth_md\": null,\n      \"comment\": null,\n      \"page_number\": 2\n    },\n    {\n      \"start_time\": \"23:45\",\n      \"end_time\": \"24:00\",\n      \"duration_hours\": 0.25,\n      \"activity\": \"Trip in hole f/ 1